import axios from 'axios';

const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const api = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
  },
});

// Данные о фильмах (в реальном проекте брались бы из БД)
export const MOVIES = {
  1: { id: 1, title: 'Эдвард руки-ножницы', year: 1990, poster_class: 'poster-1', video_url: 'https://cdn.lordfilm64.com/?token_movie=39c77691645de97a065a74efc2908f&token=ec4acf58bc9bf62f8be18cad95484c' },
  2: { id: 2, title: 'Прислуга', year: 2011, poster_class: 'poster-2', video_url: 'https://cdn.lordfilm64.com/?token_movie=e5c1c0ba38dd1e1c1f3e651d759ccb&token=ec4acf58bc9bf62f8be18cad95484c' },
  3: { id: 3, title: 'Красотка на всю голову', year: 2018, poster_class: 'poster-3', video_url: 'https://cdn.lordfilm64.com/?token_movie=304f4993c30596341d94f811992b19&token=ec4acf58bc9bf62f8be18cad95484c' },
  4: { id: 4, title: 'Достать ножи', year: 2019, poster_class: 'poster-4', video_url: 'https://player.vimeo.com/video/76979871?autoplay=1' },
  5: { id: 5, title: 'Оппенгеймер', year: 2023, poster_class: 'poster-5', video_url: 'https://player.vimeo.com/video/76979871?autoplay=1' },
  6: { id: 6, title: 'Форсаж 10', year: 2023, poster_class: 'poster-6', video_url: 'https://player.vimeo.com/video/76979871?autoplay=1' },
  7: { id: 7, title: 'Джон Уик 4', year: 2023, poster_class: 'poster-1', video_url: 'https://player.vimeo.com/video/76979871?autoplay=1' },
  8: { id: 8, title: 'Интерстеллар', year: 2014, poster_class: 'poster-3', video_url: 'https://player.vimeo.com/video/76979871?autoplay=1' },
};

// Данные для клипов
export const CLIPS = [
  { id: 1, movie_id: 1, title: 'Безумный Макс', description: 'Погоня в пустыне', video_url: 'https://cdn.lordfilm64.com/?token_movie=304f4993c30596341d94f811992b19&token=ec4acf58bc9bf62f8be18cad95484c', likes: 0, thumbnail: 'poster-1' },
  { id: 2, movie_id: 2, title: 'Дюна: Часть вторая', description: 'Полёт на черве', video_url: 'https://player.vimeo.com/video/76979871?autoplay=1', likes: 0, thumbnail: 'poster-2' },
  { id: 3, movie_id: 3, title: 'Бэтмен', description: 'Погоня в темноте', video_url: 'https://player.vimeo.com/video/76979871?autoplay=1', likes: 0, thumbnail: 'poster-3' },
  { id: 4, movie_id: 4, title: 'Достать ножи', description: 'Загадочное убийство', video_url: 'https://player.vimeo.com/video/76979871?autoplay=1', likes: 0, thumbnail: 'poster-4' },
  { id: 5, movie_id: 5, title: 'Оппенгеймер', description: 'Испытание бомбы', video_url: 'https://player.vimeo.com/video/76979871?autoplay=1', likes: 0, thumbnail: 'poster-5' }
];

export const getMovie = async (movieId) => {
  return MOVIES[movieId];
};

export const getClip = async (clipId) => {
  return CLIPS.find(c => c.id === clipId);
};

export const likeClip = async (clipId, liked) => {
  // Здесь будет запрос к бэкенду
  const clip = CLIPS.find(c => c.id === clipId);
  if (clip) {
    if (liked) {
      clip.likes += 1;
    } else {
      clip.likes = Math.max(0, clip.likes - 1);
    }
  }
  return { success: true, likes: clip?.likes || 0 };
};

export const saveMovie = async (movieId, email) => {
  // Здесь будет запрос к бэкенду
  const saved = localStorage.getItem(`saved_${email}`);
  let savedMovies = saved ? JSON.parse(saved) : [];

  if (savedMovies.includes(movieId)) {
    savedMovies = savedMovies.filter(id => id !== movieId);
    localStorage.setItem(`saved_${email}`, JSON.stringify(savedMovies));
    return { success: true, saved: false };
  } else {
    savedMovies.push(movieId);
    localStorage.setItem(`saved_${email}`, JSON.stringify(savedMovies));
    return { success: true, saved: true };
  }
};

export const checkSaved = async (movieId, email) => {
  const saved = localStorage.getItem(`saved_${email}`);
  const savedMovies = saved ? JSON.parse(saved) : [];
  return { saved: savedMovies.includes(movieId) };
};

export const registerUser = async (userData) => {
  // Здесь будет запрос к бэкенду
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      if (userData.email === 'test@test.com') {
        reject({ error: 'Email уже зарегистрирован' });
      } else {
        resolve({
          success: true,
          message: 'Регистрация успешна',
          user: { username: userData.username, email: userData.email }
        });
      }
    }, 500);
  });
};

export default api;
